module top_module(
    input wire A,
    input wire B,
    input wire CI,
    output wire SUM,
    output wire COUT
);// Instantiate a structural full adder
    wire carry_inverted, c1, c2;

    // Logic for SUM and COUT
    assign carry_inverted = A ^ B;
    assign SUM = carry_inverted ^ CI;
    assign COUT = (A & B) | (carry_inverted & CI);

endmodule
